class Animal {
    String sound() { return "..."; }
}
class Dog extends Animal {
    String sound() { return "woof"; }
}

Animal a = new Dog();
System.out.println(a.sound());

class Shape {
    String describe() { return "shape"; }
}
class Circle extends Shape {
    String describe() {
        return super.describe() + "+circle";
    }
}

System.out.println(new Circle().describe());

abstract class Vehicle {
    abstract int wheels();
    String describe() { return "vehicle with " + wheels() + " wheels"; }
}
class Bike extends Vehicle {
    int wheels() { return 2; }
}

System.out.println(new Bike().describe());
